@startuml
skinparam classAttributeIconSize 0

class Fruit {
    + show()
    + hide()
}

abstract class SlidingFruit extends Fruit {
    + show(): // animate - slide in
}

abstract class RollingFruit extends Fruit {
    + show(): // animate - roll in
}

class Banana extends SlidingFruit {
    + hide(): // animate - fade out
}

class Apple extends RollingFruit {
    + hide(): // animate - fade out
}

class Orange extends RollingFuit {
    + hide(): // animate - slide out
}

note right of "animate" : This comment describes\nthe animation behavior for each method.\nIt's not part of the standard UML syntax but helps clarify intent.

@enduml
